// ============================================================
// Process all source data into the dashboard structure.
// Reads each source node by name so it does not depend on
// merge ordering.
// ============================================================

// ── Gather raw records from each HTTP node (flatten pages) ──
function flattenJobber(nodeName, key) {
  let out = [];
  for (const item of $(nodeName).all()) {
    const nodes = item.json?.data?.[key]?.nodes || [];
    out = out.concat(nodes);
  }
  return out;
}

function flattenQB(nodeName, entity) {
  let out = [];
  for (const item of $(nodeName).all()) {
    const rows = item.json?.QueryResponse?.[entity] || [];
    out = out.concat(rows);
  }
  return out;
}

const quotes = flattenJobber('Jobber Quotes', 'quotes');
const requests = flattenJobber('Jobber Requests', 'requests');
const clients = flattenJobber('Jobber Clients', 'clients');
const qbInvoices = flattenQB('QB Invoices', 'Invoice');
const qbPayments = flattenQB('QB Payments', 'Payment');

// ── Time context ──
const now = new Date();
const year = now.getFullYear();
const MONTH_NAMES = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
const months = MONTH_NAMES.slice(0, now.getMonth() + 1);

function monthOf(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return null;
  if (d.getFullYear() !== year) return null;
  return MONTH_NAMES[d.getMonth()];
}

function emptyMonths() {
  const o = {};
  months.forEach(m => { o[m] = 0; });
  return o;
}
function emptyByPerson() {
  return { Ross: emptyMonths(), Matt: emptyMonths(), Cody: emptyMonths(), Office: emptyMonths() };
}

// ── Salesperson assignment (placeholder — refine to match data) ──
function assignPerson(quote) {
  const sp = (quote.salesperson?.name?.full || '').toLowerCase();
  if (sp.includes('ross')) return 'Ross';
  if (sp.includes('matt')) return 'Matt';
  if (sp.includes('cody')) return 'Cody';
  return 'Office';
}

// ── Revenue Produced (QB invoices) ──
const revenueProduced = emptyMonths();
for (const inv of qbInvoices) {
  const mo = monthOf(inv.TxnDate);
  if (mo && months.includes(mo)) revenueProduced[mo] += parseFloat(inv.TotalAmt) || 0;
}

// ── Cash Collected (QB payments) ──
const cashCollected = emptyMonths();
for (const p of qbPayments) {
  const mo = monthOf(p.TxnDate);
  if (mo && months.includes(mo)) cashCollected[mo] += parseFloat(p.TotalAmt) || 0;
}

// ── New Leads (clients) ──
const newLeads = emptyMonths();
for (const c of clients) {
  const mo = monthOf(c.createdAt);
  if (mo && months.includes(mo)) newLeads[mo] += 1;
}

// ── New Requests ──
const newRequests = emptyMonths();
for (const r of requests) {
  const mo = monthOf(r.createdAt);
  if (mo && months.includes(mo)) newRequests[mo] += 1;
}

// ── Quotes sent / converted / dollars ──
const quotesSentTotal = emptyMonths();
const quotesSentByPerson = emptyByPerson();
const quotesConvertedTotal = emptyMonths();
const quotesConvertedByPerson = emptyByPerson();
const convertedDollarsTotal = emptyMonths();
const convertedDollarsByPerson = emptyByPerson();

const SENT = new Set(['AWAITING_RESPONSE','CHANGES_REQUESTED','APPROVED','CONVERTED','ARCHIVED']);

for (const q of quotes) {
  const mo = monthOf(q.createdAt);
  if (!mo || !months.includes(mo)) continue;
  const status = q.quoteStatus || '';
  const person = assignPerson(q);
  const amount = parseFloat(q.amounts?.total) || 0;

  if (SENT.has(status)) {
    quotesSentTotal[mo] += 1;
    quotesSentByPerson[person][mo] += 1;
  }
  if (status === 'CONVERTED') {
    quotesConvertedTotal[mo] += 1;
    quotesConvertedByPerson[person][mo] += 1;
    convertedDollarsTotal[mo] += amount;
    convertedDollarsByPerson[person][mo] += amount;
  }
}

// ── Rounding ──
function round2(map) { for (const k of Object.keys(map)) map[k] = Math.round(map[k] * 100) / 100; return map; }
round2(revenueProduced); round2(cashCollected); round2(convertedDollarsTotal);
for (const p of Object.keys(convertedDollarsByPerson)) round2(convertedDollarsByPerson[p]);

// ── Conversion rate ──
function rate(conv, sent) {
  const o = {};
  for (const m of months) o[m] = (sent[m] || 0) > 0 ? Math.round((conv[m] / sent[m]) * 1000) / 10 : 0;
  return o;
}
const conversionRateTotal = rate(quotesConvertedTotal, quotesSentTotal);
const conversionRateByPerson = {};
for (const p of Object.keys(quotesSentByPerson)) conversionRateByPerson[p] = rate(quotesConvertedByPerson[p], quotesSentByPerson[p]);

// ── Average sale ──
function avg(dollars, conv) {
  const o = {};
  for (const m of months) o[m] = (conv[m] || 0) > 0 ? Math.round((dollars[m] / conv[m]) * 100) / 100 : 0;
  return o;
}
const avgSaleTotal = avg(convertedDollarsTotal, quotesConvertedTotal);
const avgSaleByPerson = {};
for (const p of Object.keys(quotesSentByPerson)) avgSaleByPerson[p] = avg(convertedDollarsByPerson[p], quotesConvertedByPerson[p]);

return [{
  months,
  revenueProduced,
  cashCollected,
  newLeads,
  newRequests,
  quotesSent: { total: quotesSentTotal, byPerson: quotesSentByPerson },
  quotesConverted: { total: quotesConvertedTotal, byPerson: quotesConvertedByPerson },
  conversionRate: { total: conversionRateTotal, byPerson: conversionRateByPerson },
  convertedDollars: { total: convertedDollarsTotal, byPerson: convertedDollarsByPerson },
  avgSale: { total: avgSaleTotal, byPerson: avgSaleByPerson },
  _debug: { quotes: quotes.length, requests: requests.length, clients: clients.length, invoices: qbInvoices.length, payments: qbPayments.length }
}];
